INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$AI-assisted scheduling$q$, $q$Auto-builds shift schedules based on availability, labor budget and sales forecasts, cutting the time spent manually assembling a weekly roster.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$GPS and photo time clocks$q$, $q$Employees clock in and out from a phone or shared tablet with GPS location checks and photo capture to prevent buddy punching.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Team messaging$q$, $q$Built-in chat and shift-change broadcasts keep hourly staff informed without relying on group texts or paper notices.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$POS integrations$q$, $q$Syncs with Square, Clover, Toast and Lightspeed so schedules and labor costs can be built around real sales data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Payroll add-on$q$, $q$Runs payroll directly from tracked hours and tips, reducing manual re-entry between time tracking and pay runs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Hiring and onboarding$q$, $q$Post jobs, screen applicants, run background checks and digitally onboard new hires from one dashboard.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Labor cost forecasting$q$, $q$Projects wage spend against sales in real time to help managers avoid overtime and stay within budget.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$HR and compliance tools$q$, $q$Stores employee documents and helps track break, scheduling and labor-law compliance by state and city.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Genuinely usable free Basic plan for very small teams, not just a limited trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Deep point-of-sale integrations tie labor costs directly to sales data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Combines scheduling, messaging, payroll and hiring in one product$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Mobile apps are built specifically for deskless, hourly employees$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$14-day free trial of the top plan requires no credit card$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Unlimited employees only unlock on paid Essentials tier and above$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Payroll, tip management and background checks cost extra as add-ons$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Advanced HR and compliance tools are locked behind the priciest All-in-One plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Pricing can add up quickly for multi-location businesses with add-ons enabled$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Best suited to hourly/shift businesses, less useful for salaried knowledge-worker teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Is Homebase free to use?$q$, $q$Yes. The Basic plan is free forever for up to 10 employees at a single location and includes basic scheduling, time tracking and POS integration. Larger or multi-location teams need a paid Essentials, Plus or All-in-One plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$How much does Homebase cost?$q$, $q$Paid plans start at 30 dollars per month for Essentials, rising to 70 dollars per month for Plus and 120 dollars per month for All-in-One, with roughly 20 percent off if billed annually. Payroll, tip management and background checks are separate add-ons.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Does Homebase include payroll?$q$, $q$Payroll is not bundled by default; it is an add-on priced at 39 dollars per month plus 6 dollars per employee paid, and it runs directly off tracked hours and tips.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$What industries use Homebase?$q$, $q$Homebase is built for hourly, shift-based businesses such as restaurants, retail stores, salons, healthcare practices, and home and repair services.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Does Homebase integrate with POS systems?$q$, $q$Yes, Homebase integrates with Square, Clover, Toast and Lightspeed, syncing sales data into scheduling and labor cost forecasting.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$What are the main alternatives to Homebase?$q$, $q$Common alternatives include When I Work, Deputy, 7shifts (restaurant-focused) and Sling, along with scheduling modules built into POS platforms like Toast and Square.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Restaurant shift scheduling$q$, $q$Managers build weekly schedules around sales forecasts from their POS system, reducing both understaffing and overtime costs.$q$, $q$Restaurant owners and shift managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Multi-location retail time tracking$q$, $q$Retail chains use GPS- and photo-verified time clocks across locations to prevent time theft and simplify payroll.$q$, $q$Retail operations managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Hourly team hiring and onboarding$q$, $q$Small businesses post jobs, screen applicants and digitally onboard new hourly hires without separate HR software.$q$, $q$Small business owners and HR staff$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Basic$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Up to 10 employees, 1 location","Basic scheduling and time tracking","POS integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Essentials$q$, $q$$30/month ($24/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited employees","Advanced scheduling","Advanced time tracking","Team communication"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$Plus$q$, $q$$70/month ($56/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["AI-powered scheduling","PTO controls","Departments and permissions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$All-in-One$q$, $q$$120/month ($96/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Employee onboarding","Labor cost management","HR and compliance tools"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Homebase was built specifically for businesses that run on hourly labor rather than salaried, desk-based teams. Founded in 2014 by John Waldmann and Rushi Patel in San Francisco, the company started as a scheduling and time-tracking tool and has since grown into a full workforce operating system covering scheduling, time clocks, team messaging, hiring, onboarding, payroll and HR compliance.$q$, $q$The platform is designed around the realities of restaurants, retail stores, salons and similar small businesses: unpredictable shift swaps, tip pooling, overtime rules that vary by state or city, and a workforce that mostly clocks in on a shared tablet or phone rather than a desktop computer. Homebase syncs with popular point-of-sale systems to bring sales data directly into scheduling, so managers can staff up or down based on projected demand instead of guesswork.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include drag-and-drop and AI-assisted schedule building, a shared team calendar with shift-swap and time-off requests, GPS- and photo-verified time clocks that prevent buddy punching, and built-in team messaging so managers can broadcast shift changes instantly. Labor cost forecasting tools show projected wage spend against sales in real time, helping owners avoid overtime surprises.$q$, $q$Beyond scheduling, Homebase offers hiring tools including job postings, applicant tracking and a hiring assistant, plus HR features like digital employee onboarding, document storage, and compliance tracking for break and scheduling laws. An integrated payroll add-on runs payroll directly from tracked hours, eliminating manual data entry between systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Homebase uses a freemium structure with a permanently free Basic plan for very small teams, and three paid tiers, Essentials, Plus and All-in-One, that unlock unlimited employees and progressively more advanced scheduling, HR and compliance functionality. Annual billing knocks roughly 20 percent off the monthly price on every paid tier.$q$, $q$Payroll, tip management, background checks, task management and recruiting tools are sold as optional add-ons rather than bundled by default, letting businesses pay only for what they use. A 14-day free trial of the top All-in-One tier lets new customers evaluate the full feature set before deciding which plan fits their team size and complexity.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
