INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('46a737e0-4328-492f-9496-68cfcc4a09f1', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Item organization$q$, $q$Organize belongings into categories, locations and nested sub-locations with custom fields and tags.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Full-text search$q$, $q$Quickly find any item across the entire household inventory by name, tag, location or custom field.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Photo and document attachments$q$, $q$Attach photos, receipts, manuals and warranty documents directly to each inventory item.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Warranty and maintenance tracking$q$, $q$Track purchase date, price and warranty expiration with reminders for upcoming maintenance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Single-binary Go application$q$, $q$Runs as one lightweight Go binary or Docker container with an embedded SQLite database and web UI.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Low resource footprint$q$, $q$Idle memory usage generally stays under 50MB, making it practical to run on a Raspberry Pi or small home server.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Multi-user households$q$, $q$Supports multiple user accounts so a household or shared space can jointly manage the same inventory.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Data migration from the original project$q$, $q$Preserves the original hay-kot HomeBox database schema so legacy users can upgrade without losing inventory data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Completely free and open source with no subscription or usage caps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Very lightweight, single-binary architecture that runs on minimal hardware$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Self-hosted, keeping household inventory data fully private$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Actively maintained again after the SysAdminsMedia fork revived development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Simple Docker deployment with standard, rootless and hardened image variants$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Requires self-hosting knowledge (Docker, reverse proxy, backups)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$No official first-party managed cloud hosting from the project itself$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$AGPL-3.0 license imposes source-sharing obligations on modified public deployments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Smaller community and slower feature cadence compared to commercial inventory apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Mobile experience is a responsive web app rather than a dedicated native app$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Is HomeBox free?$q$, $q$Yes, HomeBox is completely free and open source under the AGPL-3.0 license. There is no official paid tier from the project itself.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Do I need technical skills to run HomeBox?$q$, $q$Yes, HomeBox is self-hosted, so you need basic familiarity with Docker or running a Go binary on a server, NAS or Raspberry Pi. Non-technical users can pay a third-party host like ElfHosted to run it for them.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$What happened to the original HomeBox project?$q$, $q$The original project by developer hay-kot stalled in 2024 and was archived. A group called SysAdmins Media hard-forked the code and continues active development at sysadminsmedia/homebox on GitHub.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Can I migrate from the original hay-kot HomeBox?$q$, $q$Yes, the SysAdminsMedia fork migrated the original database schema forward, so existing users can upgrade to the continuation without losing their inventory data.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$What tech stack does HomeBox use?$q$, $q$HomeBox is written in Go with an embedded SQLite database and a bundled web UI, packaged as a single binary or Docker container.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$What are alternatives to HomeBox?$q$, $q$Alternatives include commercial home inventory apps like Sortly, spreadsheet-based tracking, and other self-hosted asset trackers such as Snipe-IT, which is more IT-asset focused.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Household belongings catalogue$q$, $q$Homeowners photograph and log furniture, electronics and valuables for insurance and personal reference.$q$, $q$Homeowners and renters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Warranty and receipt tracking$q$, $q$Store receipts and warranty documents alongside each item and get reminders before coverage expires.$q$, $q$Budget-conscious households$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Homelab and self-hosting stack$q$, $q$Self-hosting enthusiasts add HomeBox to an existing Docker-based homelab alongside tools like Home Assistant and Paperless-ngx.$q$, $q$Homelab and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$Self-Hosted Community Edition$q$, $q$Free$q$, $q$Free forever (AGPL-3.0 open source)$q$, NULL, $q$["Full inventory and organization feature set","Unlimited items and users","Docker, rootless and hardened deployment options","Community support on GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HomeBox is a self-hosted, open-source application for tracking everything a household owns, from electronics and furniture to documents and warranties, without handing that data to a third-party cloud service. It was created to be simple to deploy, lightweight to run, and fast to use, favoring a single Go binary and an embedded SQLite database over a heavier multi-service architecture.$q$, $q$The project changed hands in 2024 when its original creator, hay-kot, archived the repository after development stalled. A group of IT administrators operating as SysAdmins Media hard-forked the codebase, migrated the database schema forward, and resumed active development, so existing users could keep their data and continue receiving updates under the new sysadminsmedia/homebox repository.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$HomeBox lets users organize belongings into categories, locations and nested sub-locations, apply tags and custom fields, and search across the entire inventory instantly. Each item can carry photos, attached documents such as receipts or manuals, purchase price and date, and warranty or maintenance expiration tracking with reminders.$q$, $q$Because the whole stack, backend, database and frontend, ships in a single container or binary, deployment is a one-line Docker run command, and the app stays responsive even on very modest hardware like a Raspberry Pi, with idle memory usage generally under 50 megabytes.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HomeBox is free and open source under the AGPL-3.0 license, with no official paid tier, subscription, or usage limits imposed by the project itself. Anyone can download, self-host and modify it at no cost, provided any publicly hosted modified version also shares its source per the AGPL terms.$q$, $q$Users who do not want to manage their own server can pay third-party managed hosting providers, such as ElfHosted, to run a HomeBox instance for them; that hosting fee goes to the third-party provider rather than to the HomeBox project, which does not sell a first-party cloud plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('edf1831f-3d22-4a14-9dc1-185e22d2141d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Doctor diagnostics$q$, $q$Scans for disk/memory pressure, stopped containers, exposed public ports and stale backups in one command.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Butler health reports$q$, $q$Generates concise homelab health summaries with change detection since the previous check.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Crash and restart-loop detection$q$, $q$Captures pre- and post-crash logs and flags containers that are repeatedly flapping.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$One-command app installs$q$, $q$Deploys self-hosted applications via Docker Compose with a single command.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Backup and restore with verification$q$, $q$Backs up Docker volumes and runs verification drills to confirm backups are actually restorable.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Multi-server management$q$, $q$Monitors and controls multiple servers remotely over SSH from one binary.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$AI-safe MCP server$q$, $q$Lets AI tools like Claude Desktop, ChatGPT and Cursor query and act on the homelab through structured JSON, never raw shell access.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Wake-on-LAN$q$, $q$Remotely powers on sleeping machines on the local network.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Completely free, MIT-licensed, and fully open source$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Single dependency-free Go binary, easy to install and run anywhere$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$AI integration via MCP is designed to avoid exposing raw shell access$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Combines monitoring, diagnostics, backups and app installs in one tool$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Very small footprint, suitable for low-power home servers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Community side project with no formal company or SLA-backed support$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Smaller GitHub community (roughly 166 stars) compared to established homelab tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Documentation and feature set still maturing as an actively evolving project$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$No native mobile app; access is via CLI, TUI or web dashboard$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Best suited to technically confident self-hosters, not turnkey for beginners$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Is HomeButler free?$q$, $q$Yes, HomeButler is completely free and open source under the MIT license, with no paid tier or subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$What is HomeButler used for?$q$, $q$It monitors, diagnoses, backs up and self-heals a homelab, letting you manage Docker containers, servers and services from a CLI, terminal dashboard, web UI, or through AI tools via its MCP server.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Does HomeButler give AI tools SSH access to my server?$q$, $q$No. HomeButler's MCP server exposes homelab data and actions to AI assistants only through structured JSON operations, deliberately avoiding raw shell or SSH access.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$What platforms does HomeButler support?$q$, $q$It ships as a single Go binary installable via Homebrew, a curl script, npm (for the MCP component), or building from source with Go, and manages Docker, systemd and PM2 backed services.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Who created HomeButler?$q$, $q$It was created by a developer publishing under the GitHub handle Higangssh and introduced publicly via Hacker News and a DEV Community article.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$What are alternatives to HomeButler?$q$, $q$Alternatives include Uptime Kuma for status monitoring, Portainer or Dockge for container management, and Netdata for system metrics, though HomeButler combines several of these functions plus AI-safe integration in one binary.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Homelab health monitoring$q$, $q$Self-hosters run the doctor command and butler reports to catch disk, memory or container issues before they cause downtime.$q$, $q$Homelab operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$AI-assisted troubleshooting$q$, $q$Users connect HomeButler's MCP server to Claude Desktop or Cursor so an AI assistant can help diagnose issues without shell access.$q$, $q$Developers using AI coding and ops assistants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Automated backup verification$q$, $q$Admins schedule Docker volume backups with restore drills to confirm disaster recovery actually works.$q$, $q$Self-hosting enthusiasts managing critical home services$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$Open Source$q$, $q$Free$q$, $q$Free forever (MIT license)$q$, NULL, $q$["Full CLI, TUI and web dashboard","Multi-server SSH management","Backup, restore and verification","MCP server for AI tool integration"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HomeButler is a free, open-source operations tool built for people who run a homelab, a collection of self-hosted services on a home server or small cluster, and want an easy way to monitor health, catch problems early and recover automatically when something breaks. It ships as a single Go binary with zero external dependencies, so there is nothing else to install to get a CLI, a terminal dashboard, and a web UI running.$q$, $q$The project was created by a developer publishing under the handle Higangssh and was introduced through Hacker News and a DEV Community writeup explaining its central design idea: let AI assistants like Claude, ChatGPT or Cursor help manage a homelab through a structured MCP interface, without ever giving the AI raw SSH or shell access to the machine.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$HomeButler's 'doctor' command diagnoses common homelab issues such as disk and memory pressure, stopped containers, unexpectedly exposed public ports and stale backups, while its 'butler report' produces a concise health summary with change detection over time. It detects container crashes and restart loops, capturing logs before and after failures to help pinpoint root causes.$q$, $q$Beyond diagnostics, it can install self-hosted apps with one command via Docker Compose, map the topology of running containers and services across multiple servers over SSH, back up and restore Docker volumes with verification drills, and wake sleeping machines remotely via Wake-on-LAN. A built-in MCP server exposes all of this to AI tools through structured JSON rather than shell access.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HomeButler is entirely free and released under the MIT license, with the full source code available on GitHub. There is no paid tier, subscription, or commercial edition; anyone can download the binary or build it from source at no cost.$q$, $q$Because it is a community side project rather than a funded company, there is no enterprise support contract or SLA on offer; users rely on the GitHub issue tracker and community contributions for support, which is typical for a lightweight open-source infrastructure tool of this size.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c5d35463-736d-427c-b730-eb483d33b643', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Exception monitoring$q$, $q$Captures unhandled errors with full stack traces, request context, breadcrumbs and deploy correlation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Uptime monitoring$q$, $q$Pings URLs and services on a schedule and alerts the team when something goes down.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Check-Ins (cron monitoring)$q$, $q$Confirms scheduled background jobs and cron tasks actually ran, alerting on missed check-ins.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Insights log management$q$, $q$Ingests and searches structured application logs alongside error and uptime data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Deploy tracking$q$, $q$Correlates errors to specific code deploys so teams can pinpoint which release caused a regression.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Broad language support$q$, $q$Official SDKs for Ruby on Rails, Elixir/Phoenix, PHP, Python, JavaScript/Node.js, Go and Java.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Status pages$q$, $q$Public status pages that can be shared with customers to communicate incidents and uptime history.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Alert routing$q$, $q$Sends alerts to Slack, PagerDuty, Microsoft Teams, email and custom webhooks.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Free Developer plan is usable for real small projects, not just a trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Bundles error tracking, uptime and cron monitoring in one affordable product$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Bootstrapped company with a strong developer-first, no-nonsense reputation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Particularly strong, mature support for Ruby on Rails and Elixir$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Simpler pricing and setup than larger enterprise observability platforms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Smaller feature surface than full observability platforms like Datadog or Honeycomb$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Free and Team tiers cap error volume at levels that fast-growing apps can outgrow quickly$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Longer data retention and SSO require the top Business tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Smaller company size (about 30 people) means a narrower support and integration ecosystem$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Less focused on full distributed tracing compared to dedicated observability tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Is Honeybadger free?$q$, $q$Yes, the Developer plan is free forever and includes 5,000 errors per month, 1 monitor, 1 status page and 15-day retention for a single user.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$How much does Honeybadger cost?$q$, $q$Paid plans start at 26 dollars per month for Team (50,000 errors/month, unlimited users) and 80 dollars per month for Business, which adds SSO, anomaly detection and longer retention. Annual billing is discounted.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$What languages does Honeybadger support?$q$, $q$Honeybadger provides SDKs for Ruby on Rails, Elixir/Phoenix, PHP, Python, JavaScript/Node.js, Go, Java and several other languages and frameworks.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Is Honeybadger venture-backed?$q$, $q$No, Honeybadger has been self-funded and bootstrapped since it was founded in 2012, with no outside venture capital investment.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Does Honeybadger monitor uptime and cron jobs, not just errors?$q$, $q$Yes, in addition to exception monitoring, Honeybadger includes Uptime Monitoring for checking service availability and Check-Ins for verifying scheduled jobs and cron tasks actually ran.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$What are the main alternatives to Honeybadger?$q$, $q$Common alternatives include Sentry, Rollbar, Bugsnag and Airbrake for error tracking, plus Better Uptime, Pingdom or UptimeRobot for uptime checks, and Honeycomb or Datadog for teams needing broader observability.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Production error tracking for Rails apps$q$, $q$Development teams catch and triage unhandled exceptions in Ruby on Rails and Elixir applications, tied to specific deploys.$q$, $q$Ruby on Rails and Elixir development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Cron job and background task monitoring$q$, $q$Teams use Check-Ins to get alerted the moment a scheduled backup, data sync or cron job silently fails to run.$q$, $q$Backend and DevOps engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Startup application monitoring on a budget$q$, $q$Early-stage startups use the free Developer plan or low-cost Team plan to get error and uptime visibility without enterprise pricing.$q$, $q$Startup engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Developer$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["5,000 errors/month","50 MB/day logging","1 monitor, 1 status page","1 user","15-day error retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Team$q$, $q$$26/month ($286/year)$q$, $q$Monthly or annual$q$, NULL, $q$["50,000 errors/month","100 MB/day logging","5 monitors","Unlimited users","90-day error retention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$Business$q$, $q$$80/month ($880/year)$q$, $q$Monthly or annual$q$, NULL, $q$["50,000 errors/month","180-day error retention","Unlimited teams","SSO and anomaly detection"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Honeybadger began in 2012 when developers Ben Curtis, Josh Wood and Starr Horne grew fed up with their existing error-tracking tool, Airbrake, after it was acquired and service quality declined while prices rose. They built their own alternative and launched with paying customers that same year, choosing to stay self-funded and bootstrapped ever since rather than take venture capital.$q$, $q$The company remains small and distributed, based out of Kirkland, Washington, with a team of roughly 30 people. Its product bundles error tracking, uptime monitoring and scheduled job check-ins into one dashboard, aimed squarely at developers who want fast, no-nonsense visibility into production issues without a heavyweight enterprise observability platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Exception monitoring captures unhandled errors with full stack traces, request context and breadcrumbs, and ties them back to specific deploys so teams can see exactly which release introduced a regression. SDKs cover Ruby on Rails, Elixir/Phoenix, PHP, Python, JavaScript/Node.js, Go and Java, among others.$q$, $q$Uptime Monitoring checks URLs and services on a schedule and alerts on downtime, while Check-Ins verify that scheduled background jobs and cron tasks actually fired, catching silent failures that error tracking alone would miss. Alerts route through Slack, PagerDuty, Microsoft Teams, email and webhooks, and an Insights feature adds structured log search on top.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Honeybadger's Developer plan is free forever and covers 5,000 errors per month, 1 monitor and 1 status page for a single user, making it usable for side projects and very small apps. Paid Team and Business plans raise the quota to 50,000 errors per month and unlock unlimited users.$q$, $q$Team costs 26 dollars per month, or 286 dollars billed annually, while Business costs 80 dollars per month, or 880 dollars annually, and adds longer data retention, unlimited teams, SSO and anomaly detection for compliance-conscious organizations. Usage beyond plan quotas is billed per notification, and custom enterprise pricing is available for larger volumes.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7af487a9-50b6-47ff-94cd-63ca690c3618', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$High-cardinality event querying$q$, $q$Ingests wide, high-cardinality events instead of pre-aggregated metrics, enabling arbitrary ad hoc queries.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Distributed tracing$q$, $q$Visualizes requests as they move across microservices to pinpoint latency and failure sources.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$BubbleUp anomaly detection$q$, $q$Automatically highlights which dimensions correlate with an outlier or anomaly in a query or trace.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Native OpenTelemetry support$q$, $q$Ingests OpenTelemetry traces, metrics and logs directly as a founding proponent of the OTel standard.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$SLOs and triggers$q$, $q$Tracks Service Level Objectives and fires alerts through triggers when thresholds are breached.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Canvas AI Copilot$q$, $q$AI-assisted investigation tool that helps engineers explore telemetry data and surface likely causes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Honeycomb MCP server$q$, $q$Lets AI coding agents query live production telemetry directly through the Model Context Protocol.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Telemetry Pipeline$q$, $q$A separate product for routing, filtering and transforming observability data before it reaches a backend.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Generous free tier covering up to 20 million events per month$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Deep, native OpenTelemetry alignment as a founding proponent of the standard$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$BubbleUp anomaly detection speeds up root-cause analysis significantly$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Query-first architecture supports exploratory questions dashboards cannot answer$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Strong thought leadership and documentation from founders active in the observability community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Pro plan starting at 150 dollars per month can be pricier than simpler monitoring tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Enterprise pricing is custom and not transparent upfront$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Learning curve for teams used to traditional dashboard-based monitoring$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Fewer built-in integrations for non-technical business metrics compared to broader APM suites$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Full observability value requires investing in proper OpenTelemetry instrumentation$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Is Honeycomb free?$q$, $q$Yes, Honeycomb offers a Free plan covering up to 20 million events and 100 million metrics data points per month, forever, with no credit card required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Who founded Honeycomb?$q$, $q$Honeycomb was founded in 2016 in San Francisco by Charity Majors (CTO) and Christine Yen (CEO), both former engineers at Parse.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$How much does Honeycomb Pro cost?$q$, $q$Pro plans start at 150 dollars per month for up to 750 million events monthly, billed monthly or annually, and add SSO, more triggers and more SLOs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Does Honeycomb support OpenTelemetry?$q$, $q$Yes, Honeycomb is a founding proponent of OpenTelemetry and natively ingests OTel traces, metrics and logs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$What is BubbleUp in Honeycomb?$q$, $q$BubbleUp is a feature that automatically identifies which dimensions or attributes correlate with an anomaly or outlier, speeding up root-cause debugging.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$What are the main alternatives to Honeycomb?$q$, $q$Common alternatives include Datadog, New Relic, Grafana Cloud/Tempo, and Lightstep (now part of ServiceNow), along with lighter tools like Honeybadger for smaller teams.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Microservices debugging$q$, $q$Platform and SRE teams trace requests across dozens of microservices to find the exact source of latency or errors.$q$, $q$Platform engineers and SREs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Production incident response$q$, $q$On-call engineers use BubbleUp and ad hoc queries to quickly isolate the cause of an ongoing production incident.$q$, $q$DevOps and on-call engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$SLO-driven reliability management$q$, $q$Engineering leadership tracks Service Level Objectives and error budgets across services to prioritize reliability work.$q$, $q$Engineering managers and SRE leads$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Free$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Up to 20M events/month","Up to 100M metrics data points/month","2 triggers","Distributed tracing, BubbleUp, OpenTelemetry support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Pro$q$, $q$From $150/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 750M events/month","100 triggers, 2 SLOs","Single sign-on","Dedicated Honeycomb support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom (annual base allowance)$q$, NULL, $q$["300+ triggers, 100+ SLOs","Service Map","Query Data API, AWS PrivateLink","Private cloud support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Honeycomb was founded in 2016 in San Francisco by Charity Majors and Christine Yen, both of whom previously worked together at Parse, the mobile backend company acquired by Facebook. Their experience debugging complex distributed systems at Parse convinced them that traditional metrics dashboards and log searches were not enough to understand modern production software, which led directly to Honeycomb's approach of ingesting rich, high-cardinality event data that can be queried on the fly.$q$, $q$The company has become closely associated with popularizing the term 'observability' in software engineering, with Majors and Yen co-authoring the widely referenced book Observability Engineering. Honeycomb has raised approximately 150 million dollars across five funding rounds, most recently a 50 million dollar Series D in 2023, and employs roughly 100 to 250 people out of its San Francisco headquarters.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Honeycomb's core engine ingests wide, high-cardinality events rather than pre-aggregated metrics, enabling engineers to ask arbitrary exploratory questions about production behavior instead of being limited to dashboards defined in advance. Distributed tracing visualizes requests as they flow across microservices, and BubbleUp automatically surfaces which attributes correlate with an anomaly, cutting debugging time significantly.$q$, $q$The platform is a founding proponent of OpenTelemetry and ingests OTel traces, metrics and logs natively. Additional capabilities include Service Level Objectives (SLOs), triggers and alerting, a Service Map for visualizing dependencies, and newer AI features including a Canvas AI Copilot and an MCP server that lets AI coding agents query live telemetry directly.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Honeycomb's Free plan covers up to 20 million events and 100 million metrics data points per month at no cost, which is generous enough for individual projects, testing and small production workloads, and includes tracing, BubbleUp and OpenTelemetry support.$q$, $q$The Pro plan starts at 150 dollars per month for up to 750 million events monthly and adds SSO and more triggers and SLOs, while Enterprise is custom-priced around a 10-billion-events-per-year base allowance and adds a Query Data API, AWS PrivateLink, an SLO Reporting API and private cloud support for large, compliance-sensitive organizations. A separate Telemetry Pipeline product is billed from about 0.10 dollars per gigabyte for data routing and filtering.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
