INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5fe9efca-ce0e-4fb2-974d-c293416b1200', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Durable event queueing$q$, $q$Ingests inbound webhooks into a queue so temporary downtime or slowness at the destination does not lose events.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Automatic retries$q$, $q$Retries failed deliveries with configurable backoff until the destination successfully acknowledges the event.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Request and response logging$q$, $q$Records full detail of every event sent and received for debugging and auditing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Transformation and filtering$q$, $q$Reshapes and filters payloads before delivery using configurable rules.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Fan-out delivery$q$, $q$Routes a single incoming event to multiple destinations simultaneously.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Local development CLI$q$, $q$Forwards live webhooks to localhost for easier debugging during development.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Outbound webhook infrastructure$q$, $q$Lets companies send reliable webhooks to their own customers without building that infrastructure themselves.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Enterprise access controls$q$, $q$SSO, SAML and SCIM support alongside SOC 2 compliance for regulated organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Always-free Developer tier is genuinely usable for testing and small projects$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Reliable queueing and automatic retries prevent lost webhook events$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Covers both inbound receiving and outbound sending of webhooks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$CLI makes local webhook development and debugging much easier$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Founders bring deep, direct experience with the exact problem the product solves$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Growth plan at 499 dollars per month is a steep jump from the 39 dollar Team tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Enterprise pricing is custom and not published$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Small team size (under 10 people) compared to larger infrastructure vendors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Data retention on lower tiers (3 to 7 days) is short for deep historical debugging$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Usage-based overage pricing requires careful monitoring for high-volume senders$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Is Hookdeck free?$q$, $q$Yes, the Developer plan is always free and includes 10,000 events per month, 1 user and 3-day retention.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Who founded Hookdeck?$q$, $q$Hookdeck was founded in 2020 by Alexandre Bouchard (CEO) and Maurice Kherlakian (CTO), based in Montreal, Canada.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$How much does Hookdeck cost?$q$, $q$Paid plans start at 39 dollars per month for Team, 499 dollars per month for Growth, and custom pricing for Enterprise, with metered overages for events beyond each plan's included quota.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$What is an event gateway?$q$, $q$An event gateway like Hookdeck sits between event sources such as Stripe or Shopify and your application, queueing, retrying and logging every webhook so events are not lost even if your endpoint is briefly down.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Does Hookdeck help with local webhook development?$q$, $q$Yes, Hookdeck provides a CLI that forwards live webhooks to localhost, making it easier to debug integrations during development.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$What are alternatives to Hookdeck?$q$, $q$Common alternatives include Svix for webhooks-as-a-service, AWS EventBridge for general event infrastructure, and lighter tools like ngrok or Webhook.site for local testing only.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Reliable Stripe and Shopify webhook handling$q$, $q$Engineering teams route incoming Stripe or Shopify webhooks through Hookdeck to guarantee delivery even during deploys or downtime.$q$, $q$Backend engineers integrating third-party APIs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Outbound webhook infrastructure for SaaS products$q$, $q$SaaS companies use Hookdeck's outbound delivery tooling to offer reliable webhooks to their own customers without building it in-house.$q$, $q$SaaS platform and API teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Local webhook development and debugging$q$, $q$Developers use the Hookdeck CLI to forward live webhook events to localhost for faster iteration and debugging.$q$, $q$Individual developers and small engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Developer$q$, $q$Free$q$, $q$Always free$q$, NULL, $q$["10,000 events/month","1 user","3-day data retention","SOC 2 compliance"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Team$q$, $q$From $39/month$q$, $q$Monthly, pay-as-you-go for overages$q$, NULL, $q$["Unlimited users","10,000 events included, metered overages","7-day retention","Integrations and community support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Growth$q$, $q$From $499/month$q$, $q$Monthly$q$, NULL, $q$["Uptime and latency SLAs","Metrics export","SSO/SAML/SCIM","30-day retention"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Dedicated support manager","Slack Connect","Custom security and SLAs","Custom event volume"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hookdeck was founded in 2020 by Alexandre Bouchard and Maurice Kherlakian in Montreal, Canada, after the pair grew tired of losing critical webhook events from providers like Stripe, Shopify and Intercom due to timeouts, downtime or bugs in their own receiving endpoints. Rather than continuing to hand-roll retry logic and logging for every integration, they built Hookdeck as dedicated infrastructure that sits in front of any application and guarantees webhooks are queued, retried and delivered reliably.$q$, $q$The company has raised roughly 5.5 million dollars, including a 2.4 million dollar seed round backed by Matrix Partners in 2022, and operates as a lean team of under 10 people out of Montreal. It positions itself as an 'event gateway' rather than a narrow webhook tool, covering both receiving inbound events and sending reliable outbound webhooks to customers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Incoming webhooks are ingested into a durable queue with automatic retries and configurable backoff, so a slow or temporarily down destination does not result in lost events. Developers get detailed request and response logs for every event, transformation and filtering rules to reshape payloads before delivery, and fan-out delivery to route one event to multiple destinations.$q$, $q$For local development, a CLI forwards live webhooks to localhost for easier debugging, and for teams that need to send their own reliable webhooks to customers, Hookdeck offers outbound delivery infrastructure comparable to what large platforms like Stripe build in-house. Enterprise features include SOC 2 compliance, SSO/SAML/SCIM and metrics export to tools like Datadog.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hookdeck's Developer plan is always free and includes 10,000 events per month with 3-day retention, enough for testing and small projects. The Team plan starts at 39 dollars per month with unlimited users and metered overages beyond the included events.$q$, $q$The Growth plan starts at 499 dollars per month and adds uptime and latency SLAs, SSO/SAML/SCIM and 30-day retention, while Enterprise is fully custom-priced with dedicated support and negotiated SLAs. Additional event volume beyond each plan's quota is billed on a declining per-100,000-events scale, so cost per event drops significantly at higher volumes.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('36a47b1c-ff9a-44c4-8e50-572883c5348b', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
