INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Unified content calendar$q$, $q$Plans and bulk-schedules posts across Facebook, Instagram, LinkedIn, Pinterest, YouTube, TikTok and X from one dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Unified social inbox (Streams)$q$, $q$Monitors and responds to comments, mentions and messages across every connected network in one place.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Social listening and monitoring$q$, $q$Tracks brand mentions, competitors and industry trends at scale, powered by the Talkwalker acquisition.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$AI content assistant$q$, $q$Generates post captions, images and content recommendations across every pricing tier.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Custom performance reporting$q$, $q$Builds custom analytics reports on engagement, reach and campaign performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Paid social ad management$q$, $q$Manages and optimizes paid social advertising campaigns alongside organic content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Content approval workflows$q$, $q$Routes drafts through multi-step approval chains before publishing, available on Advanced and Enterprise tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Trend forecasting$q$, $q$Forecasts upcoming content and industry trends up to 90 days ahead on Professional and higher plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Extremely broad network coverage and long track record in the category$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Strong social listening and brand monitoring after the Talkwalker acquisition$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$AI assistant included on every paid tier for content generation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Robust workflow and team collaboration tools for larger marketing teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Deep third-party integration ecosystem built over more than a decade$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$No permanent free plan since March 2023, unlike several competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Starting price of 99 dollars per user per month is expensive for solo users and small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Jump from Standard to Professional (99 to 199 dollars) roughly doubles the cost for unlimited accounts$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Enterprise pricing is not published and requires a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Interface can feel dated or complex compared to newer, simpler competitors like Buffer$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Does Hootsuite have a free plan?$q$, $q$No, Hootsuite removed its permanent free plan in March 2023. It now offers a trial period of roughly 14 to 30 days on paid plans, requiring a credit card to start.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$How much does Hootsuite cost?$q$, $q$Hootsuite starts at 99 dollars per user per month for the Standard plan (annual billing), rising to 199 dollars for Professional and 399 dollars for Advanced, with custom Enterprise pricing above that.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Who founded Hootsuite?$q$, $q$Hootsuite was founded in December 2008 by Ryan Holmes, Dario Meli and David Tedman in Vancouver, Canada, evolving from an internal Twitter dashboard at Holmes's agency, Invoke Media.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$What social networks does Hootsuite support?$q$, $q$Hootsuite supports Facebook, Instagram, LinkedIn, Pinterest, YouTube, TikTok and X, among other integrations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Does Hootsuite include social listening?$q$, $q$Yes, following its 2024 acquisition of Talkwalker, Hootsuite includes brand and competitor monitoring, with full social listening available on higher-tier plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$What are the main alternatives to Hootsuite?$q$, $q$Common alternatives include Sprout Social, Buffer, Later, Agorapulse and, at the enterprise end, Sprinklr.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Multi-brand social scheduling$q$, $q$Marketing teams schedule and publish content across dozens of social accounts and brands from a single calendar.$q$, $q$Marketing teams and social media managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Brand and competitor monitoring$q$, $q$Communications teams track brand mentions, sentiment and competitor activity across social platforms in real time.$q$, $q$PR and communications teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Agency client management$q$, $q$Digital agencies manage social accounts and reporting for multiple clients from one Hootsuite workspace.$q$, $q$Digital marketing and social media agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Standard$q$, $q$$99/user/month$q$, $q$Annual (monthly option available)$q$, NULL, $q$["Up to 10 social accounts","Unlimited scheduled posts","AI post and image generation","Unified inbox and brand monitoring"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Professional$q$, $q$$199/user/month$q$, $q$Annual (monthly option available)$q$, NULL, $q$["Unlimited social accounts","Inbox automation","90-day trend forecasting","Custom performance reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Advanced$q$, $q$$399/user/month$q$, $q$Annual (monthly option available)$q$, NULL, $q$["Content approval workflows","Team message routing","Team performance metrics"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual invoicing$q$, NULL, $q$["Advanced analytics and social listening","Single sign-on (SSO)","Custom compliance solutions"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hootsuite is one of the original social media management platforms, founded in December 2008 in Vancouver by Ryan Holmes, Dario Meli and David Tedman. It began as an internal Twitter dashboard called BrightKit at Holmes's digital agency, Invoke Media, before a 2009 crowdsourced naming contest turned it into Hootsuite, named after the platform's owl logo, Owly.$q$, $q$Since then, Hootsuite has grown into a global company headquartered in Vancouver with offices in 13 cities and roughly 1,500 to 1,900 employees. It has expanded through acquisitions including Seesmic, AdEspresso, LiftMetrix, Sparkcentral and, most recently, the social listening company Talkwalker in 2024, which significantly broadened its brand monitoring and analytics capabilities.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hootsuite's dashboard lets teams schedule and publish content in bulk across Facebook, Instagram, LinkedIn, Pinterest, YouTube, TikTok and X, plan campaigns on a shared content calendar, and monitor and respond to comments and messages from a unified inbox called Streams. Social listening and competitor monitoring, powered by the Talkwalker acquisition, track brand mentions and industry trends at scale.$q$, $q$Higher tiers add content approval workflows, team message routing for customer care, custom performance reporting, and paid social ad management. An AI assistant helps generate captions and images and surface content recommendations, and enterprise customers get single sign-on and custom compliance tooling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hootsuite removed its free plan in March 2023 and now sells exclusively through paid subscriptions, starting at 99 dollars per user per month for the Standard plan, which covers up to 10 social accounts. A trial period of roughly two to four weeks is available but requires a credit card upfront.$q$, $q$Professional costs 199 dollars per user per month and unlocks unlimited social accounts and inbox automation, while Advanced costs 399 dollars per user per month and adds approval workflows and team performance metrics. Enterprise pricing is custom and includes full social listening, SSO and compliance features for large organizations.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db35ba3a-f84e-424f-82ef-b3154b5d2ca0', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Multi-protocol request builder$q$, $q$Builds and sends requests across REST, GraphQL, WebSocket, Server-Sent Events, Socket.IO and MQTT.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Progressive Web App$q$, $q$Runs directly in the browser with offline support and no installation required.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Desktop and CLI clients$q$, $q$Offers a native desktop app plus a command-line interface for running collections in CI/CD pipelines.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Pre/post-request scripting$q$, $q$Automates assertions, dynamic variables and test logic before and after each request.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Team workspaces$q$, $q$Role-based collaboration lets teams share collections and environments securely.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Self-hostable backend$q$, $q$MIT-licensed self-host Community Edition lets organizations run Hoppscotch entirely on their own infrastructure.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Built-in CORS proxy$q$, $q$Resolves cross-origin restrictions when testing APIs that would otherwise be blocked in-browser.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Customizable interface$q$, $q$Themeable UI with multiple color schemes and layout options.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Fully free core product with no signup required to start testing APIs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Genuinely open source with a real, MIT-licensed self-hosted option$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Broad protocol support including GraphQL, WebSocket and MQTT, not just REST$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Fast, lightweight browser-based Progressive Web App$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Large, active open-source community driving continuous improvement$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Smaller ecosystem of third-party integrations compared to Postman$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Enterprise-grade SSO and audit logging require the paid Self-Host Enterprise tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Team collaboration and admin features are less mature than established commercial rivals$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Small company size (roughly 8-20 people) behind a widely used product$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Documentation and mock server tooling are less extensive than Postman's$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Is Hoppscotch free?$q$, $q$Yes, Hoppscotch's core cloud product is free forever, including unlimited workspaces, collections, requests and test runners, and there is also a free, MIT-licensed self-hosted edition.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Who created Hoppscotch?$q$, $q$Hoppscotch was created by Liyas Thomas in 2019 under the name Postwoman and rebranded to Hoppscotch in 2020. The company, Hoppscotch Inc, is headquartered in Kochi, India.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Can Hoppscotch be self-hosted?$q$, $q$Yes, the Self-Host Community Edition is free and open source under the MIT license, and a paid Self-Host Enterprise Edition adds SSO, audit logs and domain whitelisting for 19 dollars per user per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$How much does the Hoppscotch Organization plan cost?$q$, $q$The Organization plan costs 6 dollars per user per month billed annually and adds an admin dashboard, dedicated support and custom payment options on top of the free tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$What protocols does Hoppscotch support?$q$, $q$Hoppscotch supports REST, GraphQL, WebSocket, Server-Sent Events, Socket.IO and MQTT, in addition to standard HTTP methods.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$What are the main alternatives to Hoppscotch?$q$, $q$Common alternatives include Postman, Insomnia, Thunder Client and Bruno, another open-source, offline-first API client.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Quick API testing without installation$q$, $q$Developers open Hoppscotch in the browser to send and inspect API requests instantly without creating an account.$q$, $q$Individual developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Self-hosted API testing for compliance$q$, $q$Security-conscious organizations self-host Hoppscotch to keep all API request and response data on their own infrastructure.$q$, $q$Enterprise engineering and security teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$CI/CD API test automation$q$, $q$Teams use the Hoppscotch CLI to run collections and assertions automatically as part of continuous integration pipelines.$q$, $q$DevOps and QA engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Free (Cloud)$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Unlimited workspaces, collections and requests","Unlimited test runners","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Organization (Cloud)$q$, $q$$6/user/month (billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Admin dashboard","Dedicated support","Custom payment options"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Self-Host Community Edition$q$, $q$Free$q$, $q$Free forever (MIT license)$q$, NULL, $q$["Full self-hosted API testing platform","Unlimited requests and collections","Community support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$Self-Host Enterprise Edition$q$, $q$$19/user/month$q$, $q$Monthly$q$, NULL, $q$["SAML-based SSO and OpenID Connect","Advanced admin tools and audit logs","Domain whitelisting","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hoppscotch began in 2019 as Postwoman, a browser-based API request builder created by Kerala-based developer Liyas Thomas. It was rebranded to Hoppscotch in 2020 following a community naming contest, and has since grown into a widely used open-source alternative to commercial tools like Postman, surpassing roughly 80,000 stars on GitHub.$q$, $q$The company behind the project, Hoppscotch Inc, is headquartered in Kochi, India, and raised a 3 million dollar seed round in late 2021 led by OSS Capital with participation from Automattic, the maker of WordPress. It remains a small, largely remote team that leans heavily on its open-source community for contributions and feature development.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hoppscotch supports building and testing requests across REST, GraphQL, WebSocket, Server-Sent Events, Socket.IO and MQTT, all from a fast, browser-based Progressive Web App that requires no installation, alongside a downloadable desktop app and a CLI for running collections in CI/CD pipelines.$q$, $q$Collections, folders and environment variables keep requests organized across projects and deployment targets, while pre-request and post-request scripting enables automated assertions and dynamic values. Team workspaces add role-based collaboration, and a built-in proxy resolves CORS restrictions when testing APIs directly from the browser.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hoppscotch's cloud Free plan costs nothing and includes unlimited workspaces, collections, requests and test runners, making the core product free forever for individuals and small teams. The Organization plan adds an admin dashboard and dedicated support for 6 dollars per user per month billed annually.$q$, $q$For organizations that must keep data on their own infrastructure, the Self-Host Community Edition is free and MIT-licensed, while a Self-Host Enterprise Edition costs 19 dollars per user per month and adds SAML SSO, OpenID Connect, audit logs and domain whitelisting for larger, security-conscious teams.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9ad514b4-f42c-4a24-9984-a035b5cef0f3', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
