-- Enrichment marathon batch: Homebase, HomeBox (SysAdminsMedia), HomeButler, Honeybadger, Honeycomb, Hookdeck, Hootsuite, Hoppscotch

-- ── Homebase ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Homebase is an all-in-one scheduling, time tracking and payroll platform built for hourly teams at restaurants, retail and small businesses.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$1,001-5,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Homebase Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Homebase offers free and paid plans for employee scheduling, time clocks, team messaging and payroll built for hourly workers at small businesses.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Homebase is an all-in-one workforce management platform purpose-built for hourly and shift-based small businesses, including restaurants, retail stores, salons, healthcare practices and other local businesses that need to schedule, communicate with and pay an hourly workforce. The company was founded in 2014 by John Waldmann and Rushi Patel and is headquartered in San Francisco, California. Homebase launched its core scheduling and time-tracking product in 2015 and has since expanded into a full suite covering employee scheduling, time clocks (web, mobile and tablet-based punch clocks), team messaging, hiring and onboarding, payroll, HR compliance document storage, and labor cost forecasting. The platform integrates with point-of-sale systems such as Square, Clover, Toast and Lightspeed, syncing sales data to help managers build labor-cost-aware schedules and forecast staffing needs. Homebase has raised roughly 189 million dollars in venture funding across five rounds: an 8 million dollar seed round, a 6 million dollar Series A in 2016 led by Khosla Ventures, a 20 million dollar Series B in 2018 led by Bain Capital Ventures, a 71 million dollar Series C in 2021 led by GGV Capital with participation from actor Matthew McConaughey, and a 60 million dollar Series D in April 2024 led by L Catterton and Emerson Collective. As of 2025 the company reported more than 3.5 million small-business employees using Homebase to log over 1.2 billion work hours, and the company employs roughly 1,900 to 1,900-plus people globally. Architecturally, Homebase is a cloud-based SaaS delivered through a responsive web dashboard plus native iOS and Android apps for both managers and employees, with a free mobile time clock app that supports GPS location tracking and photo-verified clock-ins to prevent buddy punching. Pricing follows a freemium model with four core tiers: Basic is free forever for up to 10 employees at one location with basic scheduling, time tracking and POS integration; Essentials costs 30 dollars per month, or 24 dollars per month billed annually, and unlocks unlimited employees, advanced scheduling, advanced time tracking and team communication; Plus costs 70 dollars per month, or 56 dollars annually, and adds AI-powered auto-scheduling, PTO controls, and department and permission management; and All-in-One costs 120 dollars per month, or 96 dollars annually, and adds employee onboarding, labor cost management and HR and compliance tools. Homebase also sells add-ons a la carte, including full-service payroll at 39 dollars per month base plus 6 dollars per employee paid, a tip manager at 25 dollars per month per location, background checks at 30 dollars each, a task manager at 13 dollars per month per location, and job-post boosts and a hiring assistant for recruiting. New users get a 14-day free trial of the All-in-One plan before defaulting to the free Basic tier if they do not subscribe. Homebase's target audience is small and mid-sized businesses in food service, retail, healthcare, home and repair services, and other industries that rely on hourly, deskless labor and need to reduce time spent on manual scheduling and paper timesheets while staying compliant with local scheduling and labor laws. Its most direct competitors are When I Work, Deputy, 7shifts, which focuses specifically on restaurants, Sling, and workforce modules bundled into point-of-sale systems like Toast Payroll and Square Team Management. Homebase differentiates through the combination of a genuinely usable free tier, deep POS integrations, and a broader bundled feature set spanning scheduling, payroll and hiring in one product rather than requiring several separate point solutions.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '46a737e0-4328-492f-9496-68cfcc4a09f1';

