-- ── HomeBox (SysAdminsMedia) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$HomeBox is a free, self-hosted, open-source inventory and organization system for cataloguing household items.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$HomeBox (SysAdminsMedia) Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$HomeBox is a free, self-hosted home inventory app written in Go. See how the SysAdminsMedia fork works, its features and self-hosting requirements.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HomeBox is a free, self-hosted inventory and organization system designed for home users who want to catalogue household belongings, track warranties and document purchases without relying on a spreadsheet or a paid SaaS product. The project was originally created by a developer known by the GitHub handle hay-kot, who built HomeBox as a lightweight, fast, single-binary application written in Go with an embedded SQLite database and a bundled web UI, explicitly optimized for minimal resource usage so it could run comfortably on a Raspberry Pi or small home server. After the original project stalled in 2024, with its maintainer archiving active development, a collective of IT administrators calling themselves SysAdmins Media stepped in and hard-forked the codebase to continue development under the repository sysadminsmedia/homebox on GitHub. The fork preserved backward compatibility with the original database schema, meaning existing hay-kot HomeBox users could migrate to the new continuation without losing their inventory data. The software is licensed under the GNU Affero General Public License version 3 (AGPL-3.0), which requires that any modified, network-accessible version of the code also make its source available, a common choice for community-maintained self-hosted infrastructure tools. Technically, HomeBox ships as a single Go binary and as Docker images, including standard, rootless and hardened container variants, published to the GitHub Container Registry. A typical deployment runs entirely in a Docker container with idle memory usage generally under 50 megabytes, and the entire stack, backend API, SQLite database and frontend web UI, is embedded in one artifact rather than requiring separate services. Core features include organizing items into categories, locations and nested sub-locations with custom fields, tagging, full-text search across the entire inventory, photo and document attachments per item so users can store receipts, manuals and warranty documents alongside the physical object record, tracking of purchase date, purchase price and current value, and maintenance and warranty expiration tracking with reminders. The interface is a responsive web app that works on desktop, tablet and mobile browsers, and it supports multi-user accounts within a household or shared space. Because it is entirely open source and self-hosted, there is no official pricing or subscription; users run it themselves on their own hardware, a home NAS, a Raspberry Pi, a VPS, or a managed container platform, and third-party hosts such as ElfHosted offer paid managed HomeBox instances for people who do not want to self-host, though that hosting is not operated by the HomeBox project itself. The target audience is technically inclined homeowners, renters, preppers, insurance-conscious households, and self-hosting and homelab enthusiasts who already run other self-hosted services (Home Assistant, Immich, Paperless-ngx, and similar tools) and want a lightweight, private alternative to consumer inventory apps. Competing options include commercial or hybrid home inventory apps such as Sortly and Nest Egg, spreadsheet-based DIY tracking, and other self-hosted asset trackers like Snipe-IT, which is more oriented toward IT asset management than general household belongings. HomeBox differentiates itself through its explicit home-user focus, its extremely small resource footprint compared to heavier self-hosted stacks, its single-binary simplicity that avoids the multi-container complexity of many self-hosted apps, and its active community-driven continuation after the original creator stepped away, which has kept the project receiving regular releases, bug fixes and new features rather than going stale.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'edf1831f-3d22-4a14-9dc1-185e22d2141d';

