-- ── HomeButler ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$HomeButler is a free, open-source single-binary tool for monitoring, backing up and self-healing a homelab from chat, AI or terminal.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$HomeButler Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$HomeButler is a free, open-source Go binary that monitors, backs up and self-heals a homelab via CLI, web dashboard, or AI tools through MCP.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HomeButler is an open-source homelab management tool distributed as a single, dependency-free Go binary that gives self-hosters a way to monitor, control, back up and automatically recover their home server infrastructure from the command line, a terminal dashboard, a web UI, or directly through AI assistants like Claude Desktop, ChatGPT and Cursor. It was created by a developer using the GitHub handle Higangssh, who published the project on GitHub under the MIT license and introduced it publicly through Hacker News Show HN posts and a companion DEV Community article titled 'I don't want to give Claude SSH access to my home server,' which explains the project's core design philosophy: AI tools can inspect and act on a homelab through a structured Model Context Protocol (MCP) server that HomeButler exposes, without ever being granted raw shell or SSH access to the underlying machines. This addresses a common concern among homelab operators who want to use AI copilots for infrastructure troubleshooting but do not want to expose their servers to arbitrary command execution by a language model. Technically, HomeButler is built primarily in Go (roughly 94 percent of the codebase) with a Svelte-based frontend embedded directly into the binary via Go's go:embed feature, so there is no separate Node.js runtime or web server to install; the compiled binary bundles a CLI, a terminal UI dashboard built with the Bubble Tea framework, and a full web dashboard in roughly 15 megabytes. Core functionality includes a 'butler report' feature that generates concise health summaries of the homelab with change detection since the last check, a 'doctor' diagnostic command that flags common problems like disk or memory pressure, stopped containers, unexpectedly exposed public ports and stale backups, one-command installation of self-hosted applications via Docker Compose, inventory and topology mapping of running containers and services across multiple servers, crash and restart-loop detection that captures pre- and post-crash logs and flags containers that are repeatedly flapping, Docker volume backup and restore with verification drills to confirm backups are actually restorable, multi-server management over SSH, Wake-on-LAN support for powering on sleeping machines remotely, and the built-in MCP server that lets AI tools query and act on the homelab only through defined, structured JSON operations rather than shell access. Installation is available through Homebrew, a one-line curl installer that auto-detects OS and architecture, npm for the MCP component, or building from source with Go and a Makefile, with GoReleaser used to produce cross-platform release binaries; as of mid-2026 the project had reached roughly its 36th release at version 0.19.2. HomeButler is entirely free and open source with no paid tier, subscription or company behind it in the traditional sense; it functions as an independent, community-driven side project rather than a funded startup, and the GitHub repository shows a modest but active community of around 166 stars and 11 forks at the time of research. Its target audience is homelab operators and self-hosting enthusiasts who already run Docker-based services at home (Plex, Home Assistant, Immich, and similar stacks) and want a lightweight operations layer for monitoring and recovery without deploying a heavier observability stack. Comparable tools include Uptime Kuma for status monitoring, Portainer and Dockge for container management, Netdata for system metrics, and general infrastructure-as-code or backup tools like Duplicati or Restic used piecemeal; HomeButler differentiates by combining monitoring, diagnostics, one-command app installs, backup verification and AI-safe MCP integration into one dependency-free binary rather than requiring several separate self-hosted tools stitched together.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c5d35463-736d-427c-b730-eb483d33b643';

