-- ── Honeycomb ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Honeycomb is an observability platform for distributed tracing, metrics and debugging production software, built by former Parse and Facebook engineers.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Honeycomb Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Honeycomb is an observability and tracing platform founded by Charity Majors and Christine Yen. Compare its free, Pro and Enterprise pricing plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Honeycomb is an observability platform focused on distributed tracing, high-cardinality event analysis and production debugging for modern, cloud-native software systems. It was founded in 2016 in San Francisco by Charity Majors and Christine Yen, who had previously worked together at Parse, the mobile backend-as-a-service company acquired by Facebook, where they experienced firsthand the difficulty of debugging complex distributed systems with traditional metrics and log-based tools. Majors, who serves as CTO, and Yen, who serves as CEO, built Honeycomb around the idea that engineers need to be able to ask arbitrary, exploratory questions about their production systems in real time rather than being limited to pre-aggregated dashboards, a philosophy the company and its founders have championed publicly as part of the broader 'observability' movement in software engineering, including co-authoring the O'Reilly book 'Observability Engineering.' Honeycomb is headquartered in San Francisco, California, and has raised a total of roughly 150 million dollars in venture funding across five rounds: an initial 4 million dollar seed round, an 11.4 million dollar Series A in 2019, a 20 million dollar Series B in 2020, a 50 million dollar Series C in 2021, and a 50 million dollar Series D in April 2023, backed by investors including Scale Venture Partners and Insight Partners. As of 2026 the company employs roughly 100 to 250 people. Technically, Honeycomb ingests high-cardinality, high-dimensionality event data (wide events) rather than pre-aggregated metrics, and stores it in a proprietary columnar store built for fast, arbitrary querying at scale; it is a founding member and heavy proponent of OpenTelemetry, the open-source instrumentation standard, and supports ingesting OpenTelemetry traces, metrics and logs directly. Core capabilities include distributed tracing across microservices, BubbleUp, a feature that automatically highlights which dimensions correlate with an anomaly or outlier in a trace or query, Service Level Objective (SLO) tracking, triggers and alerting, a query builder for ad hoc exploration without predefined dashboards, and more recently an AI-assisted 'Canvas' copilot and a Honeycomb MCP server that lets AI coding agents query production telemetry directly. Honeycomb also sells a separate Telemetry Pipeline product for routing, filtering and transforming observability data before it reaches a backend, priced from around 0.10 dollars per gigabyte. Pricing follows a freemium model with three tiers: the Free plan costs nothing and includes up to 20 million events per month and up to 100 million metrics data points per month, along with 2 triggers, distributed tracing, BubbleUp, OpenTelemetry support and the Canvas AI Copilot, making it usable for solo developers and small projects; the Pro plan starts at 150 dollars per month, billed monthly or annually, and raises limits to 750 million events per month and 3.75 billion metrics data points per month while adding 100 triggers, 2 SLOs, single sign-on and dedicated Honeycomb support; and the Enterprise plan is custom-priced, typically anchored around a base allowance of 10 billion events annually, and adds 300-plus triggers, 100-plus SLOs, a service map, a Query Data API, AWS PrivateLink connectivity, an SLO Reporting API and private cloud deployment options. Honeycomb's target audience is engineering teams running microservices and distributed, cloud-native architectures, particularly platform, SRE and backend teams that have outgrown traditional metrics-and-logs monitoring and need to debug novel, unpredictable production issues quickly. Its most direct competitors are Datadog, New Relic, Grafana Labs (including Grafana Tempo and Grafana Cloud), Lightstep (now part of ServiceNow), and Honeybadger for teams with lighter needs; Honeycomb differentiates through its high-cardinality, query-first approach to observability rather than dashboard-first metrics, its deep OpenTelemetry alignment, and its founders' thought leadership in defining the modern observability category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5fe9efca-ce0e-4fb2-974d-c293416b1200';

