  short_description = COALESCE($q$Hookdeck is an event gateway that receives, queues, transforms and reliably delivers webhooks and asynchronous events for developers.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Montreal, Quebec, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Hookdeck Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Hookdeck is a webhook and event gateway built by Alexandre Bouchard and Maurice Kherlakian. Compare its Developer, Team, Growth and Enterprise pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Hookdeck is an event gateway, essentially managed infrastructure for receiving, queueing, transforming and reliably delivering webhooks and other asynchronous events between services, built for engineering teams that rely on event-driven architectures. It was founded in 2020 by Alexandre Bouchard, who serves as CEO and previously worked as a product designer and full-stack engineer, and Maurice Kherlakian, who serves as CTO and brought more than 20 years of systems architecture experience. The founders built Hookdeck after repeatedly losing hours to missed or mishandled webhook events from providers like Shopify, Stripe and Intercom in their own past projects, and concluded that engineering teams needed a dedicated, purpose-built event gateway rather than hand-rolled webhook receivers and retry logic. The company is headquartered in Montreal, Quebec, Canada, and has raised approximately 5.5 million dollars in funding, including a 2.4 million dollar seed round announced in April 2022 backed by investors such as Matrix Partners, with advisors drawn from companies including Shopify, Checkout.com, Gorgias, LogDNA and Doppler. As a small, focused team of roughly 8 to 10 employees, Hookdeck has positioned itself as core infrastructure that reportedly processes billions of events for thousands of developers and companies. Technically, Hookdeck sits between event sources (Stripe, Shopify, Twilio, GitHub, and any custom webhook sender) and an application's own endpoints, ingesting incoming webhook requests into a durable queue so that a slow or temporarily unavailable receiving service does not cause lost events; it provides automatic retries with configurable backoff, request transformation and filtering rules, fan-out delivery to multiple destinations, and detailed request/response logging so developers can inspect exactly what was sent and received for debugging. It also offers outbound event delivery tooling for companies that need to send reliable webhooks to their own customers, effectively letting a company build a Stripe-style reliable webhook product without building that infrastructure themselves. Hookdeck integrates with local development workflows via a CLI that forwards webhooks to localhost, similar in spirit to tools like ngrok but purpose-built for webhook testing, and supports SOC 2 compliance, SSO/SAML/SCIM for enterprise access control, and metrics export to tools like Datadog on higher tiers. Pricing follows a freemium, usage-based model with four tiers: the Developer plan is always free and includes 10,000 events per month, 1 user and 3-day data retention; the Team plan starts at 39 dollars per month, covers unlimited users, includes 10,000 events with metered overages, and provides 7-day retention plus integrations and community support; the Growth plan starts at 499 dollars per month, adds uptime and latency SLAs, metrics export, SSO/SAML/SCIM and a read-only user role with 30-day retention; and the Enterprise plan is custom-priced with dedicated premium support, a support manager, Slack Connect access and custom security and SLA terms. Beyond the included quota, additional events are billed on a sliding per-100,000-events scale that decreases at higher volumes, from roughly 3.00 dollars per 100,000 events at lower volumes down to about 0.35 dollars per 100,000 events beyond 500 million monthly events, and throughput-based pricing is also available starting around 3.00 dollars per event-per-second at low throughput, declining to about 1.00 dollar per event-per-second at 1,000-plus events per second. Hookdeck's target audience is backend and platform engineering teams building on event-driven or webhook-heavy architectures, including companies integrating deeply with providers like Stripe, Shopify and Twilio, as well as SaaS companies that need to offer reliable outbound webhooks to their own customers. Its most direct competitors are Svix, another dedicated webhooks-as-a-service platform, along with more general message queue and event infrastructure like AWS EventBridge, and lighter-weight local development tools such as ngrok and Webhook.site that only solve part of the problem. Hookdeck differentiates through its focus on reliability (durable queueing, automatic retries, full observability into every event) and by covering both inbound webhook receiving and outbound webhook sending in a single gateway product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '36a47b1c-ff9a-44c4-8e50-572883c5348b';

