-- ── Hoppscotch ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Hoppscotch is an open-source API development ecosystem for testing REST, GraphQL, WebSocket and other protocols, built as a Postman alternative.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Kochi, Kerala, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Hoppscotch Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Hoppscotch is an open-source API testing tool and Postman alternative founded by Liyas Thomas. Compare its free, Organization and self-host pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Hoppscotch is an open-source API development ecosystem that lets developers build, test, document and share API requests across REST, GraphQL, WebSocket, Server-Sent Events, Socket.IO and MQTT protocols, positioned as a lightweight, fast and fully open-source alternative to commercial tools like Postman and Insomnia. The project was created by Liyas Thomas, a developer based in Kochi, Kerala, India, who first launched it in 2019 under the name Postwoman as a browser-based API request builder. On its first anniversary in 2020 the project was rebranded to Hoppscotch, with the new name crowdsourced from its community, and it has since grown into one of the most starred open-source developer tools on GitHub, surpassing roughly 78,000 to 80,000 stars and counting organizations such as Google, Microsoft, Salesforce and IBM among its users. Hoppscotch operates as a company, Hoppscotch Inc, headquartered in Kochi, India, and raised a 3 million dollar seed round in December 2021 led by OSS Capital, with participation from Automattic, the company behind WordPress, and angel investors including Austen Allred; OSS Capital founder Joseph Jacks joined Hoppscotch's board following the round. The company remains a lean, largely remote team, reported at anywhere from roughly 8 to 20 people depending on the source, reflecting its open-source, community-driven development model where a large share of feature development comes from outside contributors. Technically, the Hoppscotch web and desktop client is built primarily with Vue.js and TypeScript on the frontend, with a Rust component used for performance-sensitive request handling, and the product ships as a browser-based Progressive Web App with offline support, a downloadable desktop application, and a command-line interface for running collections in CI/CD pipelines; the self-hostable backend and admin dashboard are also open source, licensed under the MIT license, and can be deployed via Docker for organizations that want to keep all API testing data on their own infrastructure. Core features include a request builder supporting all major HTTP methods plus GraphQL, WebSocket, SSE, Socket.IO and MQTT, collections and folders for organizing requests, environment variables for managing different deployment targets, pre-request and post-request scripting for automated tests and dynamic values, request history, team workspaces with role-based access control for collaboration, a built-in proxy to work around CORS restrictions when testing browser-inaccessible APIs, and a customizable, themeable interface. Pricing follows a freemium, dual cloud/self-host model: the Free plan costs nothing forever and includes unlimited workspaces, collections, requests and test runners with community support on Hoppscotch's hosted cloud service; the Organization plan costs 6 dollars per user per month billed annually (with a higher monthly rate available) and adds an admin dashboard, dedicated support and custom payment options; separately, the Self-Host Community Edition is free and open source under the MIT license for organizations that want to run Hoppscotch entirely on their own servers; and a Self-Host Enterprise Edition costs 19 dollars per user per month billed monthly and adds SAML-based single sign-on, OpenID Connect, advanced admin tools, audit logs and domain whitelisting for larger, security-conscious organizations. Hoppscotch's target audience spans individual developers and open-source contributors who want a fast, free, no-signup-required API client, through to engineering teams and enterprises that need self-hosted, compliant API testing infrastructure with SSO and audit logging. Its most direct competitors are Postman, the dominant commercial API platform it was explicitly built as an alternative to, along with Insomnia, Thunder Client, and Bruno, another open-source, offline-first API client; Hoppscotch differentiates through being fully open source with a genuinely usable self-hosted option, a browser-first Progressive Web App experience that requires no installation, and broad protocol support beyond plain REST, including GraphQL and realtime protocols like WebSocket and MQTT that some competitors handle less natively.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9ad514b4-f42c-4a24-9984-a035b5cef0f3';

